os:store.os:value:
#[output application/json --- {
                contactId: vars.contactId,
                projectId: vars.projectId,
                unitId: vars.unitId
            }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
var msg = lower(vars.messageText default "")
var quickReply = vars.quickReplyValue
---
{
    messages: [
        {
            text: if (msg contains "payment" or quickReply == "view_payments")
                    "Your payment summary is available in the Finance tab. You have upcoming installments due. Would you like me to show details?"
                  else if (msg contains "service" or msg contains "maintenance" or quickReply == "request_service")
                    "I can help you create a service request. Please go to the Services tab and tap 'New Request', or tell me what issue you're experiencing."
                  else if (msg contains "unit" or msg contains "status")
                    "Your unit details and current status are shown on the Dashboard. Is there something specific you'd like to know?"
                  else if (msg contains "launch" or msg contains "new project")
                    "Check the New Launches tab for exciting upcoming projects! You can join the waitlist directly from the app."
                  else if (msg contains "warranty" or msg contains "asset")
                    "You can view all your unit's assets and their warranty status in the Assets tab."
                  else
                    "I understand you're asking about: '" ++ (vars.messageText default "") ++ "'. Let me help you with that. Could you provide more details?",
            sender: "agent",
            timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"},
            quickReplies: [
                { label: "View payments", value: "view_payments" },
                { label: "Request service", value: "request_service" },
                { label: "Unit status", value: "unit_status" },
                { label: "New launches", value: "new_launches" }
            ]
        }
    ]
}

%dw 2.0
output application/json
---
{
    message: "Push token registered successfully"
}
